var partnerEndpoints = map[string]string{
    "partner-a": "https://api.partner-a.com/data",
    "partner-b": "https://api.partner-b.com/data",
}

func (h *Handler) FetchPartnerData(w http.ResponseWriter, r *http.Request) {
    partnerID := r.URL.Query().Get("partner")
    endpoint, ok := partnerEndpoints[partnerID]
    if !ok {
        http.Error(w, "unknown partner", 400)
        return
    }
    resp, err := http.Get(endpoint)
    if err != nil { http.Error(w, err.Error(), 500); return }
    defer resp.Body.Close()
    io.Copy(w, resp.Body)
}
